public void insert(boolean _skipMarkup)
{
    AgreementHeader agreementHeader;

    //CS - Abhinav - Creation of sales order number from salesAgreeement
    if(this.MatchingAgreement && ETGCanadaParameters::find().EnableNewSONumberSequence)
    {
        SalesTable salestableCount;

        select count(RecId) from salestableCount
            where salestableCount.MatchingAgreement == this.MatchingAgreement;

        SalesAgreementHeader SalesAgreementHeader = SalesAgreementHeader::find(this.MatchingAgreement);

        str connector = salestableCount.RecId > 9 ? '' : '0';
        int postfix = salestableCount.RecId + 1;
        this.SalesId = SalesAgreementHeader.SalesNumberSequence + ' - ' + connector + int2Str(postfix) ;        
    }
    //CE - Abhinav

    next insert(_skipMarkup);

    if (this.MatchingAgreement)
    {
        select firstonly DefaultDimension from agreementHeader  where  agreementHeader.RecId == this.MatchingAgreement;

        if (agreementHeader.DefaultDimension && agreementHeader.DefaultDimension != this.DefaultDimension)
        {
            this.DefaultDimension = agreementHeader.DefaultDimension;
            this.doUpdate();
        }
    }
}

public boolean  canSubmitToWorkflow(str workflowType)
{
    boolean     canSubmit = next canSubmitToWorkflow(workflowType);

    if(ETGACFParameters::find().EnableSOWorkflow == NoYes::Yes)
    {
        if (this.RecId && this.ETGWorkflowStatus  == VersioningDocumentState::Draft)
        {
            canSubmit = true;
        }
    }

    return canSubmit;
}

public static void  updateWorkflowStatus(RefRecId salesTableRecId , VersioningDocumentState status)
{
    SalesTable salesTable;

    ttsbegin;

    salesTable = SalesTable::findRecId(salesTableRecId, true);
    if(salesTable)
    {
        salesTable.ETGWorkflowStatus = status;
        salesTable.doUpdate();
    }

    ttscommit;
}

